import akka.actor.{Actor, ActorRef, ActorSystem, Props}
import akka.pattern.ask
import akka.util.Timeout

import scala.concurrent.duration._
import scala.concurrent.{Await, ExecutionContext, Future}

// Message protocol
sealed trait AccountMessage
case class Deposit(amount: BigDecimal) extends AccountMessage
case class Withdraw(amount: BigDecimal) extends AccountMessage
case object GetBalance extends AccountMessage

// Response protocol
sealed trait AccountResponse
case class BalanceUpdated(newBalance: BigDecimal) extends AccountResponse
case class InsufficientFunds(currentBalance: BigDecimal, requestedAmount: BigDecimal) extends AccountResponse
case class InvalidAmount(amount: BigDecimal) extends AccountResponse
case class CurrentBalance(balance: BigDecimal) extends AccountResponse

/**
 * AccountActor manages a single account's balance.
 *
 * Akka actors process one message at a time from their mailbox,
 * which means the mutable `balance` variable is effectively
 * thread-confined to the actor's execution context. No explicit
 * synchronization is needed because the actor model guarantees
 * serial message processing — this eliminates race conditions
 * while maintaining high throughput.
 *
 * IMPORTANT: Do NOT close over `balance` in Futures or callbacks
 * outside this actor, as that would break the confinement guarantee.
 */
class AccountActor(accountId: String, initialBalance: BigDecimal = BigDecimal(0)) extends Actor {

  // This var is safe because Akka guarantees that only one message
  // is processed at a time within a single actor instance.
  // The actor mailbox serializes all access to this mutable state.
  private var balance: BigDecimal = initialBalance

  override def receive: Receive = {
    case Deposit(amount) =>
      if (amount <= 0) {
        sender() ! InvalidAmount(amount)
      } else {
        balance += amount
        sender() ! BalanceUpdated(balance)
      }

    case Withdraw(amount) =>
      if (amount <= 0) {
        sender() ! InvalidAmount(amount)
      } else if (balance < amount) {
        sender() ! InsufficientFunds(balance, amount)
      } else {
        balance -= amount
        sender() ! BalanceUpdated(balance)
      }

    case GetBalance =>
      sender() ! CurrentBalance(balance)
  }
}

object AccountActor {
  def props(accountId: String, initialBalance: BigDecimal = BigDecimal(0)): Props =
    Props(new AccountActor(accountId, initialBalance))
}

/**
 * AccountManager routes messages to the correct account actor,
 * creating account actors on demand. This also processes messages
 * one at a time, so the mutable map is safe.
 */
class AccountManager extends Actor {

  private var accounts: Map[String, ActorRef] = Map.empty

  override def receive: Receive = {
    case (accountId: String, msg: AccountMessage) =>
      val accountActor = accounts.getOrElse(accountId, {
        val ref = context.actorOf(AccountActor.props(accountId), s"account-$accountId")
        accounts += (accountId -> ref)
        ref
      })
      accountActor.forward(msg)
  }
}

object AccountManager {
  def props: Props = Props(new AccountManager)
}

// Demo application
object FinancialSystem extends App {
  val system = ActorSystem("FinancialSystem")
  implicit val timeout: Timeout = Timeout(5.seconds)
  implicit val ec: ExecutionContext = system.dispatcher

  val manager = system.actorOf(AccountManager.props, "account-manager")

  // Simulate concurrent transactions
  val futures: Seq[Future[Any]] = (1 to 100).map { i =>
    val accountId = s"ACC-${i % 5}" // 5 accounts
    val msg = if (i % 3 == 0) {
      Withdraw(BigDecimal(10))
    } else {
      Deposit(BigDecimal(50))
    }
    manager ? (accountId, msg)
  }

  val results = Future.sequence(futures)

  results.foreach { responses =>
    responses.foreach {
      case BalanceUpdated(b) => println(s"Balance updated: $b")
      case InsufficientFunds(b, r) => println(s"Insufficient funds: balance=$b, requested=$r")
      case InvalidAmount(a) => println(s"Invalid amount: $a")
      case other => println(s"Unexpected: $other")
    }

    // Query final balances
    val balanceFutures = (0 until 5).map { i =>
      val accountId = s"ACC-$i"
      (manager ? (accountId, GetBalance)).mapTo[CurrentBalance].map(b => (accountId, b.balance))
    }

    Future.sequence(balanceFutures).foreach { balances =>
      println("\n=== Final Balances ===")
      balances.foreach { case (id, bal) =>
        println(s"$id: $bal")
      }
      system.terminate()
    }
  }

  Await.result(system.whenTerminated, 30.seconds)
}